def safe_int(campo, valor):
    try:
        return (True, int(str(valor).strip()), None)
    except (TypeError, ValueError) as e:
        return (False, None, f"{campo}: no convertible a int ({e})")

print(safe_int("edad", " 21 "))
print(safe_int("edad", "x"))

from decimal import Decimal, InvalidOperation, ROUND_HALF_UP

def parse_edad_monto(edad_txt, monto_txt):
    raw = {"edad": edad_txt, "monto": monto_txt}
    errors = []
    clean = {}
    try:
        clean["edad"] = int(str(edad_txt).strip())
    except (TypeError, ValueError):
        errors.append("edad: inválida")
        clean["edad"] = None
    try:
        m = Decimal(str(monto_txt).strip().replace(",", "."))
        clean["monto"] = m.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    except (InvalidOperation, AttributeError):
        errors.append("monto: inválido")
        clean["monto"] = None
    return {"raw": raw, "clean": clean, "errors": errors}

print(parse_edad_monto(" 30 ", "10,5"))
print(parse_edad_monto("x", "abc"))

