from decimal import Decimal, InvalidOperation, ROUND_HALF_UP

def parse_monto(texto: str):
    s = (texto or "").strip()
    if not s:
        return (False, None, "monto vacío")
    try:
        val = Decimal(s.replace(",", "."))
        if not val.is_finite():
            return (False, None, "monto no finito")
        q = val.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        return (True, q, None)
    except InvalidOperation:
        return (False, None, "monto no parseable")

for t in ["10.5", "3,25", "", "abc"]:
    print(t, parse_monto(t))

def simular_intake(nombres: str, contacto: str, edad: str) -> dict:
    return {
        "nombres": nombres.strip(),
        "contacto": contacto.strip(),
        "edad_raw": edad,
        "edad": int(edad.strip()) if str(edad).strip().isdigit() else None,
    }

print(simular_intake(" Ana ", " 999 ", "30"))
